<script setup lang="ts">
import { type Essences } from '@/sheet/stores/hero/heroStore';

const props = defineProps<{
  essences: Essences;
  allowMultiple?: boolean;
}>();

const toggleEssence = (index: keyof Essences) => {
  if (!props.allowMultiple) {
    for (const key in props.essences) {
      if (key !== index) {
        props.essences[key as keyof Essences] = false;
      }
    }
  }
  props.essences[index] = !props.essences[index];
}
</script>

